const raw = $input.first().json.content[0].text || $input.first().json.text || '';
let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json\n?/g, '').replace(/```/g, '').trim();
}
const parsed = JSON.parse(cleaned);
return [{
  json: {
    concept: parsed.concept,
    clothes: parsed.clothes,
    background: parsed.background,
    shots: parsed.shots,
    reelNumber: $('Set Transcription').item.json.reelNumber,
    avatarImageUrl: $('Set Transcription').item.json.avatarImageUrl,
    timing: $('Set Transcription').item.json.timing
  }
}];

const klingResponse = $input.first().json;
const shot = $('Split Into Shots').item.json;

// Kling may return task_id for async polling - handle both sync and async
const imageUrl = klingResponse.data?.[0]?.url 
  || klingResponse.images?.[0]?.url 
  || klingResponse.output?.url 
  || klingResponse.url 
  || null;

const taskId = klingResponse.task_id || klingResponse.id || null;

return [{
  json: {
    shotNumber: shot.shot_number,
    shotName: shot.shot_name,
    cameraMotion: shot.camera_motion,
    durationSeconds: shot.duration_seconds,
    imageUrl: imageUrl,
    taskId: taskId,
    reelNumber: $('Set Reference Image URL').item.json.reelNumber
  }
}];

// This node runs after all shots are processed
// Aggregate all uploaded file info
const items = $input.all();
const reelNumber = items[0].json.reelNumber || $('Set Reference Image URL').item.json.reelNumber;
return [{
  json: {
    reelNumber: reelNumber,
    totalShots: items.length,
    uploadedFiles: items.map(i => ({
      name: i.json.name,
      id: i.json.id,
      webViewLink: i.json.webViewLink
    }))
  }
}];

// Input: Reel number to process
// This node sets up Phase 2 context
return [{
  json: {
    reelNumber: $input.first().json.reelNumber || 'ENTER_REEL_NUMBER'
  }
}];

// FFMPEG Stitch Placeholder
// This would be replaced with an SSH node or HTTP call to your VPS
// to run FFMPEG and stitch video clips with the song audio

// Expected FFMPEG command pattern:
// ffmpeg -i clip1.mp4 -i clip2.mp4 -i clip3.mp4 \
//   -filter_complex '[0:v][1:v][2:v]concat=n=3:v=1[v]' \
//   -map '[v]' -i song.mp3 -shortest output.mp4

const reelNumber = $('Phase 2 - Set Reel Number').item.json.reelNumber;

return [{
  json: {
    status: 'ffmpeg_placeholder',
    message: 'Replace this node with SSH Execute node to run FFMPEG on your VPS',
    reelNumber: reelNumber,
    outputFileName: `Reel_${reelNumber}_final.mp4`,
    suggestedCommand: `ffmpeg -f concat -safe 0 -i /tmp/reel_${reelNumber}/clips.txt -i /tmp/reel_${reelNumber}/song.mp3 -c:v copy -c:a aac -shortest /tmp/reel_${reelNumber}/output.mp4`
  }
}];

