const response = $input.first().json;

// Extract text from Gemini response structure
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Clean markdown if present
let cleaned = rawText.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json\n?/g, '').replace(/```/g, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse Gemini JSON response: ' + rawText.substring(0, 200));
}

// Carry forward all context
const ctx = $('7. Merge Avatar URLs + All Data').item.json;

return [{
  json: {
    reelNumber: ctx.reelNumber,
    accountToPost: ctx.accountToPost,
    reelType: ctx.reelType,
    timing: ctx.timing,
    songLink: ctx.songLink,
    songConcept: parsed.song_concept,
    selectedAvatars: parsed.selected_avatars,
    clothes: parsed.clothes,
    background: parsed.background,
    nanobanaReferencePrompt: parsed.nanobana_reference_prompt,
    shots: parsed.shots,
    totalShots: parsed.shots.length
  }
}];

// Build the avatar URLs array from selected avatars
const data = $input.first().json;
const avatarUrls = data.selectedAvatars.map(a => a.avatar_url).filter(u => u && u.trim() !== '');

return [{
  json: {
    ...data,
    avatarUrlsForNanobana: avatarUrls,
    avatarUrlsString: avatarUrls.join(', ')
  }
}];

const nanobanaResponse = $input.first().json;
const ctx = $('10. Prepare Nanobana Input').item.json;

// Extract image URL from Nanobana response - adjust field name per their API docs
const referenceImageUrl = nanobanaResponse.image_url 
  || nanobanaResponse.url 
  || nanobanaResponse.output?.url
  || nanobanaResponse.data?.url
  || nanobanaResponse.result?.url;

if (!referenceImageUrl) {
  throw new Error('Could not find image URL in Nanobana response: ' + JSON.stringify(nanobanaResponse).substring(0, 200));
}

return [{
  json: {
    ...ctx,
    referenceImageUrl: referenceImageUrl
  }
}];

const falResponse = $input.first().json;
const shot = $('16. Split Into Individual Shots').item.json;
const ctx = $('15. Merge Folder ID + Context').item.json;

// Extract image URL from fal.ai response
const imageUrl = falResponse.images?.[0]?.url
  || falResponse.image?.url
  || falResponse.url
  || falResponse.output?.[0];

if (!imageUrl) {
  throw new Error('No image URL in fal.ai response: ' + JSON.stringify(falResponse).substring(0, 200));
}

return [{
  json: {
    shotNumber: shot.shot_number,
    shotName: shot.shot_name,
    cameraMotion: shot.camera_motion,
    durationSeconds: shot.duration_seconds,
    imagePrompt: shot.image_generation_prompt,
    imageUrl: imageUrl,
    reviewFolderId: ctx.reviewFolderId,
    reviewFolderLink: ctx.reviewFolderLink,
    reelNumber: ctx.reelNumber,
    fileName: `shot_${shot.shot_number}_${shot.shot_name}.png`
  }
}];
